fill((0,10)--(2.5,5)--(5,10)--cycle,red);
fill((10,0)--(7.5,5)--(5,0)--cycle,green);
fill((10,10)--(7.5,5)--(5,10)--cycle,green);
fill((0,0)--(2.5,5)--(0,10)--cycle,blue);
fill((10,0)--(7.5,5)--(10,10)--cycle,blue);
